(12955, '2026-04920', NULL, NULL, 2, 'Accion Correctiva', 0, NULL, 7, 'SAT ALMERIA', 2, 'Asignado', 3, 'No Urgente', 'NO', '2026-02-27 14:34:00', '2026-03-02', '07:30:00', '2026-03-02', '15:30:00', NULL, '00:00', 464, 'COSTA JOVEN ESPAÑA S.A.', 'ESX11000004', 162, 'ALM-ANDRES RIVAS TRUJILLO', 2432, '5886-MOTRIL-NUEVA', 'NUEVA', 'MOTRIL', '18600', 'Granada', 161, 'OFT-DAVID SANCHEZ ORTEGA', 112, 'ALM-ROBERTO AGUILAR MESA', NULL, NULL, NULL, 'NO', 'NO', 'EQUIPO CON ERROR ALARMA FUNCIONAMIENTO EN VENTILACION', NULL, 'ANOTAR QUÉ EQUIPO ESTÁ AVERIADO', 'EQUIPO CON ERROR ALARMA FUNCIONAMIENTO EN VENTILACION', 'Detectar motor ventilador averiado en equipo zona caballero ', 'NO', NULL, 'NO', NULL),
(12956, '2026-04921', 'S/26/00128 - TARIFA AVISOS - C', NULL, 38, 'Presupuesto', 0, NULL, 9, 'Departamento Técnico', 1, 'Sin Asignar', 0, NULL, 'NO', '2026-02-27 14:48:00', NULL, NULL, NULL, NULL, NULL, NULL, 673, 'Nordic Climate Systems B.V. (Spain)', 'ESX11000017', 0, NULL, 3301, 'Nordic Climate Systems B.V. (Spain)', 'PASEO CASTELLANA, 91 PLT 14', 'Madrid', '28046', 'Madrid', 140, 'SEV-VICTOR BLAZQUEZ MUÑOZ', NULL, NULL, NULL, NULL, NULL, 'NO', 'NO', '- 1 TARIFAS AVISOS/CORRECTIVOS: \n\nLABORABLES (Laborables de 8h a 16h): \nServicio mínimo facturable (trabajos inferiores a 1 hora de trabajo: 125€  \nHora de servicio (Técnico oficial + ayudante especialista): 75€/h \nBloque desplazamiento desde base* (radio 30 km):  50€/ud \nKm desde base*: 0,45 €/km \n\nFUERA DE HORARIO LABORAL / sábados / domingos / festivos: \nServicio mínimo facturable (trabajos inferiores a 1 hora de trabajo: 150€  \nHora de servicio (Técnico oficial + ayudante especialista): 90€/h \nHora desplazamiento desde base* (radio 20 km): 60€/ud \nKm adicional: 0,60 €/km\n\nTIEMPOS MAXIMOS DE RESPUESTA: \nAvería ordinaria (no afecta al funcionamiento del equipo): -48h \nAvería urgente (afecta al funcionamiento / equipo parado): -12h\n\n*Base: Capital de provincia\n- 1 CANALES DE COMUNICACION Y COORDINACION: \n\nPara garantizar un servicio ordenado, eficiente y sin incidencias, será imprescindible que las comunicaciones y solicitudes se realicen exclusivamente por los siguientes canales: \n\nCorreo electrónico: sat@climasur.es \n\nTeléfono para urgencias: 607 56 04 25 \n\nNo se atenderán solicitudes enviadas por otras vías ni aquellas que no se ajusten a las condiciones de servicio acordadas.\n- 1 FORMA DE PAGO: \n\nConfirming bancario 45 días\n', NULL, 'Nº Ppto. Odoo: S/26/00128 - TARIFA AVISOS - Nordic Climate Systems B.V. (Spain)\nRef. Ppto. Odoo: S/26/00128\nComercial: FRANCISCO JAVIER UBEDA CAPEL\n', '- 1 TARIFAS AVISOS/CORRECTIVOS: \n\nLABORABLES (Laborables de 8h a 16h): \nServicio mínimo facturable (trabajos inferiores a 1 hora de trabajo: 125€  \nHora de servicio (Técnico oficial + ayudante especialista): 75€/h \nBloque desplazamiento desde base* (radio 30 km):  50€/ud \nKm desde base*: 0,45 €/km \n\nFUERA DE HORARIO LABORAL / sábados / domingos / festivos: \nServicio mínimo facturable (trabajos inferiores a 1 hora de trabajo: 150€  \nHora de servicio (Técnico oficial + ayudante especialista): 90€/h \nHora desplazamiento desde base* (radio 20 km): 60€/ud \nKm adicional: 0,60 €/km\n\nTIEMPOS MAXIMOS DE RESPUESTA: \nAvería ordinaria (no afecta al funcionamiento del equipo): -48h \nAvería urgente (afecta al funcionamiento / equipo parado): -12h\n\n*Base: Capital de provincia\n- 1 CANALES DE COMUNICACION Y COORDINACION: \n\nPara garantizar un servicio ordenado, eficiente y sin incidencias, será imprescindible que las comunicaciones y solicitudes se realicen exclusivamente por los siguientes canales: \n\nCorreo electrónico: sat@climasur.es \n\nTeléfono para urgencias: 607 56 04 25 \n\nNo se atenderán solicitudes enviadas por otras vías ni aquellas que no se ajusten a las condiciones de servicio acordadas.\n- 1 FORMA DE PAGO: \n\nConfirming bancario 45 días\n', NULL, 'NO', NULL, 'NO', NULL),
(12957, '2026-04922', '16309227', '16309227', 2, 'Accion Correctiva', 0, NULL, 16, 'SAT SEVILLA/HUELVA', 7, 'Albaranado', 3, 'No Urgente', 'NO', '2026-02-28 13:09:00', '2026-02-28', '10:00:00', '2026-02-28', '11:00:00', '2026-03-01 11:25:28', '00:00', 591, 'MODA SUR, S.A.', 'ESX11000001', 152, 'ADM-RAFAEL MORALES JIMENEZ', 2378, '303 SEV-PLAZA NUEVA', 'PLAZA CENTRAL 12', 'SEVILLA', '41002', 'Sevilla', 161, 'OFT-DAVID SANCHEZ ORTEGA', 142, 'SEV-ALEJANDRO DURAN SALAS', '2.0', 'SAT', NULL, 'NO', 'NO', 'Nº Pedido 16309227 INC000026029278 WR000977198 Hace bastante calor en la planta 0,1 y 2 del edificio de mujer ', 'solucionado por teléfono', NULL, 'Nº Pedido 16309227 INC000026029278 WR000977198 Hace bastante calor en la planta 0,1 y 2 del edificio de mujer ', 'se habla con tienda y a petición del encargado y debido a las temperaturas que tenemos actualmente en Sevilla se cambian todas las unidades de planta cero planta uno y planta dos a veintidós grados modo frío', 'NO', NULL, 'NO', NULL),
(12958, '2026-04923', 'PTE', NULL, 2, 'Accion Correctiva', 0, NULL, 16, 'SAT SEVILLA/HUELVA', 1, 'Sin Asignar', 3, 'No Urgente', 'NO', '2026-03-02 08:16:00', NULL, '00:00:00', NULL, '00:00:00', NULL, '00:00', 35, 'SERVICIOS TECNICOS ANDALUCES, S.L', 'ESX11000016', 152, 'ADM-RAFAEL MORALES JIMENEZ', 2942, 'BOSTON T50 CC LAGOH', 'AVDA. DE PALMAS ALTAS, 1', 'Sevilla', '41012', 'Sevilla', 147, 'OFT-PABLO HERRERA MOLINA', NULL, NULL, NULL, NULL, NULL, 'NO', 'NO', 'MTO FEBRERO BOSTON T50 CC LAGOH', NULL, NULL, 'MTO FEBRERO BOSTON T50 CC LAGOH', NULL, 'NO', NULL, 'NO', NULL),
(12959, '2026-04924', '16309955', NULL, 2, 'Accion Correctiva', 0, NULL, 5, 'SAT MALAGA', 555, 'No facturar', 3, 'No Urgente', 'NO', '2026-03-02 09:13:00', '2026-03-02', '00:00:00', '2026-03-02', '02:00:00', '2026-03-02 12:18:37', '00:00', 438, 'BRISA SPORT SA', 'ESX11000002', 130, 'ADM-CARMEN LOPEZ FERNANDEZ', 2569, '13857-1-13857 MAL-EL INGENIO', 'AVDA.DEL REY JUAN CARLOS I, 29700 VÉLEZ-MÁLAGA', 'VELEZ MÁLAGA', '29700', 'Málaga', 133, 'OFT-SERGIO TORRES REYES', 135, 'MAL-DANIEL CASTAÑO RUEDA', NULL, NULL, NULL, 'NO', 'NO', 'WR000977637 Hace frio en superficie de tienda', NULL, NULL, 'WR000977637 Hace frio en superficie de tienda', 'Se llama a tienda en reiteradas ocasiones y no me lo cogen. Llamo a ClimaControl y vemos que la tienda está en 23,5 grados en ventas para 24 de consigna, y con los equipos funcionando correctamente. Se ajusta la consigna por el día de hoy a 24,5 grados. Tras varias llamadas consigo hablar con tienda y me indican que el aviso debió ser del sábado porque la encargada abrió a las 9 está mañana y el aviso es anterior. Ahora mismo me indican que están bien. cerrado ', 'NO', NULL, 'NO', NULL),
(12960, '2026-04925', '16310061', NULL, 2, 'Accion Correctiva', 0, NULL, 5, 'SAT MALAGA', 7, 'Albaranado', 3, 'No Urgente', 'NO', '2026-03-02 09:36:00', '2026-03-02', '02:00:00', '2026-03-02', '04:00:00', '2026-03-02 12:57:03', '02:00', 438, 'BRISA SPORT SA', 'ESX11000002', 130, 'ADM-CARMEN LOPEZ FERNANDEZ', 2592, '7866 MAL-MARQUES LARIOS', 'C/ MARQUÉS DE LARIOS, 5, 29005', 'MÁLAGA', '29005', 'Málaga', 133, 'OFT-SERGIO TORRES REYES', 135, 'MAL-DANIEL CASTAÑO RUEDA', NULL, NULL, NULL, 'NO', 'NO', 'Nº Pedido 16310061 INC000026027715 WR000976859 No enciende\r\n', NULL, 'WR000976859 No enciende\r\n', 'Nº Pedido 16310061 INC000026027715 WR000976859 No enciende\r\n', 'A mi llegada los equipos se encuentran funcionando con normalidad. Reviso en plataforma ENERGYMON los históricos correspondientes a la fecha indicada, comprobando consignas, temperaturas y posibles alarmas, sin detectar comportamiento anómalo.\r\n\r\nSe realiza comprobación in situ de los equipos, verificando funcionamiento en frío, temperaturas de impulsión y correcto trabajo de compresores y ventiladores. Se mantiene en observación durante la intervención sin reproducirse la incidencia.\r\n\r\nNo se detecta fallo en la instalación de climatización.\r\nSe cierra aviso por funcionamiento correcto.', 'NO', NULL, 'NO', NULL),
(12961, '2026-04926', NULL, NULL, 39, 'Visita Tecnica (No Facturable)', 0, NULL, 7, 'SAT ALMERIA', 5, 'Finalizado', 3, 'No Urgente', 'NO', '2026-03-02 09:37:00', '2026-03-05', '07:45:00', '2026-03-05', '08:45:00', '2026-03-05 15:08:49', '00:00', 395, 'DISTRIBUCIONES IBERIA S.A.', 'ESX11000010', 0, NULL, 3083, 'C4462 CTRA. SIERRA ALHAMILLA', 'AVDA. DE SIERRA ALHAMILLA, S/N', 'Almeria', '4004', 'Almería', 161, 'OFT-DAVID SANCHEZ ORTEGA', 112, 'ALM-ROBERTO AGUILAR MESA', NULL, NULL, NULL, 'NO', 'NO', 'VISITA TECNICA', 'Visita Técnica', NULL, 'VISITA TECNICA', 'Visita técnica por cambio de ubicación de equipos clima', 'NO', NULL, 'NO', NULL);
INSERT INTO `intervenciones` (`cod_incidencia`, `num_intervencion`, `orden_servicio`, `numero_pedido`, `cod_tipo`, `tipo`, `cod_sintoma`, `sintoma`, `cod_departamento`, `departamento`, `cod_estado`, `estado`, `cod_prioridad`, `prioridad`, `es_cita`, `fecha_incidencia`, `fecha_asignacion`, `hora_asignacion`, `fecha_fin_asig`, `hora_fin_asignacion`, `fecha_finalizacion`, `duracion_planificada`, `cod_cliente`, `cliente`, `cif`, `cod_agente`, `nombre_agente`, `cod_sede`, `sede`, `direccion_sede`, `localidad_sede`, `cp_sede`, `provincia_sede`, `cod_responsable`, `responsable`, `cod_tecnico`, `nombre_tecnico`, `codigos_personal`, `nombres_personal`, `tipo_mantenimiento`, `vinculado_obra`, `vinculado_mantenimiento`, `arealizar`, `notas_internas`, `notas_aviso`, `a_realizar`, `realizado`, `req_informe`, `obs_informe`, `req_presupuesto`, `obs_presupuesto`) VALUES
(12962, '2026-04927', 'PTE', NULL, 2, 'Accion Correctiva', 0, NULL, 16, 'SAT SEVILLA/HUELVA', 7, 'Albaranado', 3, 'No Urgente', 'NO', '2026-03-02 09:51:00', '2026-03-02', '01:00:00', '2026-03-02', '02:00:00', '2026-03-02 10:38:18', '02:00', 591, 'MODA SUR, S.A.', 'ESX11000001', 152, 'ADM-RAFAEL MORALES JIMENEZ', 2314, '12462-OUTLET MALL SEV-LAGOH', 'AVDA.DE PALMAS ALTAS, 41012 SEVILLA', 'SEVILLA', '41012', 'Sevilla', 147, 'OFT-PABLO HERRERA MOLINA', 140, 'SEV-VICTOR BLAZQUEZ MUÑOZ', NULL, NULL, NULL, 'NO', 'NO', 'ECO427677 Informarles que en ClimaControl hemos detectado que la tienda Outlet Mall 12462 SEV-LAGOH, SEVILLA tiene activa la alerta Control remoto termostato es distinto a control remoto lo que nos indica que el sistema de control de climatización se encuentra en modo manual (Termostato) y puede estar generando consumos indeseados.', '[C]', '[COMPLETO]', 'ECO427677 Informarles que en ClimaControl hemos detectado que la tienda Outlet Mall 12462 SEV-LAGOH, SEVILLA tiene activa la alerta Control remoto termostato es distinto a control remoto lo que nos indica que el sistema de control de climatización se encuentra en modo manual (Termostato) y puede estar generando consumos indeseados.', 'Me avisan porque desde ClimaControl el sistema aparece en manual y con las máquinas paradas. Hablo con tienda para que lo pongan en automático, pero me comentan que a ellos les sigue figurando en manual y que no arranca nada.\r\n\r\nMe desplazo a tienda y reviso el cuadro eléctrico, comprobando que el selector manual/automático está en posición manual porque se había bajado por error el interruptor contiguo. Lo coloco correctamente en automático y verifico que las unidades arrancan.\r\n\r\nCompruebo una por una que todas las máquinas inician funcionamiento normal y que no queda ninguna bloqueada. Me quedo en tienda supervisando el arranque completo del sistema y verificando desde control que no se generen nuevas alarmas.\r\n\r\nPermanezco el tiempo necesario hasta que la tienda empieza a recuperar temperatura de confort y confirmo estabilidad de funcionamiento. Posteriormente contacto con ClimaControl para verificar que ya les aparece el sistema en automático y operativo, procediendo al cierre de la eco generada.\r\n\r\nTrabajo finalizado sin más incidencia.', 'NO', NULL, 'NO', NULL),
(12963, '2026-04928', 'S/26/00129 - Mantenimiento UPH', NULL, 38, 'Presupuesto', 0, NULL, 13, 'SAT GRANADA', 99, 'Anulado', 3, 'No Urgente', 'NO', '2026-03-02 10:15:00', NULL, '00:00:00', NULL, '00:00:00', NULL, '00:00', 16, 'ENERGIA PACIFICO SA', 'ESX11000006', 0, NULL, 18, 'ENERGIA PACIFICO SA', 'AVDA. DE LA BORBOLLA, 60', 'Sevilla', '41004', 'Sevilla', 152, 'ADM-RAFAEL MORALES JIMENEZ', NULL, NULL, NULL, NULL, NULL, 'NO', 'NO', '- Revisión de mantenimiento de climatización en la agrupación UPH SUR Agrupación Granada 2026\r\n- 1 Operaciones Preventivas R.I.T.E (Equipos Aire Acondicionado) 1,00\r\nOperaciones preventivas a realizar en sus instalaciones de\r\nclimatización en cumplimiento del RD 178/2021/RITE (Reglamento\r\npara Instalaciones Térmicas en los Edificios), según el listado que\r\nse indica en la IT3 y siguientes. En estas operaciones no se incluye\r\nlas piezas o recambios a sustituir, así como la mano de obra que se\r\nconsideran averías correctivas. En este mismo caso de no incluidas\r\nse encuentran los aceites y refrigerantes.\r\nFrecuencia ANUAL: Centro y equipamiento a revisar\r\nAcciones a realizar:\r\n1 Revisión y limpieza de la batería del condensador\r\n2 Comprobación del funcionamiento de la bomba de condensados\r\n3 Comprobación del estado de los compresores. Verificar el nivel de aceite.\r\n4 Revisión del sifón y tubo de drenaje\r\n5 Comprobar el correcto funcionamiento del termostato (mando a distancia)\r\n6 Revisión y limpieza del filtro del aire. S/P Sustituir.\r\n7 Revisión de carga de refrigerante (estanqueidad, ausencia de fugas), y\r\nreponer, si procede, anotando cuantía.\r\n8 Revisión del asilamiento de las tuberías frigoríficas\r\n9 Revisión general de estanqueidad de juntas de unión\r\n10 Comprobar funcionamiento del equipo\r\n11 \"Tomar datos según protocolo.\r\n - Datos frigoríficos, presiones, temperaturas, así como los suministrados\r\npor el autómata de la máquina.\r\n - Medición de consumos de resistencias.\r\n - Medida de tensión y consumos y comparación con los nominales.\r\n - Anotar valores control de condiciones ambientales.\"\r\n12 Revisión y limpieza de la bandeja de condensados\r\n13 Comprobación del estado de los ventiladores. Verificación\r\nde inexistencia de ruidos y\r\n vibraciones.\r\n14 Revisión de anclajes (bancada)\r\n15 Revisión del estado de la carcasa (unidad exterior)\r\n16 Revisión y reapriete de bornas del cuadro eléctrico y\r\nconexiones. Inspección y limpieza de\r\n cuadros eléctricos.\r\n17 Revisión envolvente y embellecedores (unidad interior)\r\n18 Revisión del estado de turbinas y aspas\r\n19 Comprobar aislamiento eléctrico\r\n20 Verificar puesta a tierra\r\n- CENTRAL DILAR\r\n- 2 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 2 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 2 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento  a instalación/caseta ubicada fuera del centro de trabajo a una distancia 10 < x ≤ 30 km\r\n- CENTRAL DURCAL\r\n- 2 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 2 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 2 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia 30 < x ≤ 60 km\r\n- CENTRAL DUQUE\r\n- 1 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 1 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 1 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia x >60 km\r\n- CENTRAL PAMPANEIRA\r\n- 3 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 3 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 3 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia x >60 km\r\n- CENTRAL POQUEIRA\r\n- 2 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 2 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 2 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia x >60 km\r\n- CENTRAL NUEVO CASTILLO\r\n- 3 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 3 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 3 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia 30 < x ≤ 60 km\r\n- CENTRAL NEGRATIN\r\n- 1 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 1 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 1 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia x >60 km\r\n- CENTRAL CANALES\r\n- 3 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 3 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 3 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 [7.43_Servicio_Desplazamiento_4] 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia 30 < x ≤ 60 km\r\n- CENTRAL IZBOR\r\n- 4 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 4 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 4 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 [7.43_Servicio_Desplazamiento_5] 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia x >60 km\r\n- CENTRAL CAZULAS\r\n- 1 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 1 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 1 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 [7.43_Servicio_Desplazamiento_5] 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia x >60 km\r\n', 'GILBERTO 02/03: presupuesto aprobado - MANTENIMIENTO.\r\nanulo intervención porque el mantenimiento se factura desde contratos odoo.', 'Nº Ppto. Odoo: S/26/00129 - Mantenimiento UPH SUR Agrupación Granada 2026 - ENERGIA PACIFICO SA\r\nRef. Ppto. Odoo: S/26/00129\r\nComercial: RAFAEL MORALES JIMENEZ\r\n', '- Revisión de mantenimiento de climatización en la agrupación UPH SUR Agrupación Granada 2026\r\n- 1 Operaciones Preventivas R.I.T.E (Equipos Aire Acondicionado) 1,00\r\nOperaciones preventivas a realizar en sus instalaciones de\r\nclimatización en cumplimiento del RD 178/2021/RITE (Reglamento\r\npara Instalaciones Térmicas en los Edificios), según el listado que\r\nse indica en la IT3 y siguientes. En estas operaciones no se incluye\r\nlas piezas o recambios a sustituir, así como la mano de obra que se\r\nconsideran averías correctivas. En este mismo caso de no incluidas\r\nse encuentran los aceites y refrigerantes.\r\nFrecuencia ANUAL: Centro y equipamiento a revisar\r\nAcciones a realizar:\r\n1 Revisión y limpieza de la batería del condensador\r\n2 Comprobación del funcionamiento de la bomba de condensados\r\n3 Comprobación del estado de los compresores. Verificar el nivel de aceite.\r\n4 Revisión del sifón y tubo de drenaje\r\n5 Comprobar el correcto funcionamiento del termostato (mando a distancia)\r\n6 Revisión y limpieza del filtro del aire. S/P Sustituir.\r\n7 Revisión de carga de refrigerante (estanqueidad, ausencia de fugas), y\r\nreponer, si procede, anotando cuantía.\r\n8 Revisión del asilamiento de las tuberías frigoríficas\r\n9 Revisión general de estanqueidad de juntas de unión\r\n10 Comprobar funcionamiento del equipo\r\n11 \"Tomar datos según protocolo.\r\n - Datos frigoríficos, presiones, temperaturas, así como los suministrados\r\npor el autómata de la máquina.\r\n - Medición de consumos de resistencias.\r\n - Medida de tensión y consumos y comparación con los nominales.\r\n - Anotar valores control de condiciones ambientales.\"\r\n12 Revisión y limpieza de la bandeja de condensados\r\n13 Comprobación del estado de los ventiladores. Verificación\r\nde inexistencia de ruidos y\r\n vibraciones.\r\n14 Revisión de anclajes (bancada)\r\n15 Revisión del estado de la carcasa (unidad exterior)\r\n16 Revisión y reapriete de bornas del cuadro eléctrico y\r\nconexiones. Inspección y limpieza de\r\n cuadros eléctricos.\r\n17 Revisión envolvente y embellecedores (unidad interior)\r\n18 Revisión del estado de turbinas y aspas\r\n19 Comprobar aislamiento eléctrico\r\n20 Verificar puesta a tierra\r\n- CENTRAL DILAR\r\n- 2 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 2 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 2 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento  a instalación/caseta ubicada fuera del centro de trabajo a una distancia 10 < x ≤ 30 km\r\n- CENTRAL DURCAL\r\n- 2 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 2 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 2 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia 30 < x ≤ 60 km\r\n- CENTRAL DUQUE\r\n- 1 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 1 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 1 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia x >60 km\r\n- CENTRAL PAMPANEIRA\r\n- 3 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 3 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 3 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia x >60 km\r\n- CENTRAL POQUEIRA\r\n- 2 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 2 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 2 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia x >60 km\r\n- CENTRAL NUEVO CASTILLO\r\n- 3 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 3 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 3 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia 30 < x ≤ 60 km\r\n- CENTRAL NEGRATIN\r\n- 1 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 1 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 1 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia x >60 km\r\n- CENTRAL CANALES\r\n- 3 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 3 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 3 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 [7.43_Servicio_Desplazamiento_4] 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia 30 < x ≤ 60 km\r\n- CENTRAL IZBOR\r\n- 4 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 4 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 4 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 [7.43_Servicio_Desplazamiento_5] 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia x >60 km\r\n- CENTRAL CAZULAS\r\n- 1 [7.02_Servicio_Split_M] 7.02 Servicio 02. Splits - Internvenciones  M.\r\n- 1 [7.02_Servicio_Split_3M] 7.02 Servicio 02. Splits - Intervenciones 3M.\r\n- 1 [7.02_Servicio_Split_A] 7.02 Servicio 02. Splits - Intervenciones A.\r\n- 1 [7.43_Servicio_Desplazamiento_5] 7.43 Servicio 43.  Gastos de implantación servicio de mantenimiento a instalación/caseta ubicada fuera del centro de trabajo a una distancia x >60 km\r\n', NULL, 'NO', NULL, 'NO', NULL),
(12964, '2026-04929', '16310332', NULL, 2, 'Accion Correctiva', 0, NULL, 16, 'SAT SEVILLA/HUELVA', 555, 'No facturar', 3, 'No Urgente', 'NO', '2026-03-02 10:37:00', '2026-03-02', '02:00:00', '2026-03-02', '03:00:00', '2026-03-02 11:49:55', '00:00', 100, 'NOVA URBAN ESPAÑA SA', 'ESX11000003', 152, 'ADM-RAFAEL MORALES JIMENEZ', 2544, '304 SEV-CC EL MIRADOR', 'CC EL MIRADOR, AVDA. PRINCIPAL S/N', 'SEVILLA', '41007', 'Sevilla', 147, 'OFT-PABLO HERRERA MOLINA', 164, 'SEV-MARCOS GUTIERREZ CANO', NULL, NULL, NULL, 'NO', 'NO', 'WR000977939 El aire acondicionado sigue dando muchisimo calor', NULL, NULL, 'WR000977939 El aire acondicionado sigue dando muchisimo calor', 'solucionado por telefono ', 'NO', NULL, 'NO', NULL),
(12965, '2026-04930', 'PTE', NULL, 2, 'Accion Correctiva', 0, NULL, 5, 'SAT MALAGA', 7, 'Albaranado', 1, 'Urgente', 'NO', '2026-03-02 10:35:00', '2026-03-02', '16:00:00', '2026-03-02', '17:00:00', '2026-03-02 13:03:57', '02:00', 281, 'GRUPO ELEGANCE MODA, S.A', 'ESX11000011', 130, 'ADM-CARMEN LOPEZ FERNANDEZ', 2488, '4217 MARB-MARINA BANUS', 'C/ RAMON ARECES, S/N', 'MARBELLA', '29660', 'Málaga', 161, 'OFT-DAVID SANCHEZ ORTEGA', 105, 'MAL-JORGE MENDEZ PRIETO', '2.0', 'SAT', NULL, 'NO', 'NO', 'La tienda no presenta coumicación en ENERGYMON. Realizar diagnóstico ', NULL, NULL, 'La tienda no presenta coumicación en ENERGYMON. Realizar diagnóstico ', 'Se revisa el PLC tras aviso de mal funcionamiento en el sistema de control. Compruebo que la pantalla táctil se encuentra bloqueada, sin responder al pulsarla, impidiendo el acceso a menús y parámetros.\r\n\r\nSe realizan varias comprobaciones para descartar fallo de comunicación o alimentación, verificando tensiones, estado de conexiones y comunicación con los equipos asociados. Confirmado que el problema está en el bloqueo del propio panel, se procede a realizar reinicio completo del PLC, dejando el sistema sin tensión y arrancándolo nuevamente para restablecer funcionamiento y comunicaciones.\r\n\r\nTras el reinicio, la pantalla vuelve a responder correctamente. Se comprueba acceso a menús, lectura de parámetros y correcta comunicación con los equipos de climatización. Permanezco en observación verificando que no vuelve a bloquearse y que el sistema trabaja con normalidad.\r\n\r\nSistema operativo y funcionando correctamente.\r\nTrabajo finalizado.', 'NO', NULL, 'NO', NULL),
(12966, '2026-04931', '16310313', NULL, 2, 'Accion Correctiva', 0, NULL, 16, 'SAT SEVILLA/HUELVA', 555, 'No facturar', 3, 'No Urgente', 'NO', '2026-03-02 10:39:00', '2026-03-02', '08:00:00', '2026-03-02', '09:00:00', '2026-03-02 10:46:21', '00:00', 281, 'GRUPO ELEGANCE MODA, S.A', 'ESX11000011', 152, 'ADM-RAFAEL MORALES JIMENEZ', 2854, '12523-SEV-LAGOH', 'Centro comercial Lagoh, 41012 Sevilla', 'Sevilla', '41012', 'Sevilla', 147, 'OFT-PABLO HERRERA MOLINA', 164, 'SEV-MARCOS GUTIERREZ CANO', NULL, NULL, NULL, 'NO', 'NO', 'WR000977905 No funciona el aire de tienda, la temperatura es muy elevada y hace mucha calor.', NULL, NULL, 'WR000977905 No funciona el aire de tienda, la temperatura es muy elevada y hace mucha calor.', 'solucionado por telefono', 'NO', NULL, 'NO', NULL),
(12967, '2026-04932', '16310340', NULL, 2, 'Accion Correctiva', 0, NULL, 5, 'SAT MALAGA', 7, 'Albaranado', 3, 'No Urgente', 'NO', '2026-03-02 10:40:00', '2026-03-02', '05:00:00', '2026-03-02', '07:00:00', '2026-03-02 13:44:47', '00:00', 281, 'GRUPO ELEGANCE MODA, S.A', 'ESX11000011', 130, 'ADM-CARMEN LOPEZ FERNANDEZ', 2478, '12530 MAL-MARQUES LARIOS', 'ALLE MARQUÉS DE LARIOS, 9, 29015 MÁLAGA', 'MÁLAGA', '29015', 'Málaga', 133, 'OFT-SERGIO TORRES REYES', 135, 'MAL-DANIEL CASTAÑO RUEDA', NULL, NULL, NULL, 'NO', 'NO', 'Nº Pedido 16310340 INC000026033026 WR000977940 REVISION SPLIT COCINA. sale agua, no succiona', NULL, NULL, 'Nº Pedido 16310340 INC000026033026 WR000977940 REVISION SPLIT COCINA. sale agua, no succiona', 'Acudo a tienda por aviso en Split de cocina debido a fallo en evacuación de condensados. A la revisión se comprueba que la bomba de condensados se encontraba bloqueada por acumulación progresiva de residuos orgánicos propios del ambiente de cocina, lo que impedía el correcto movimiento del flotador de nivel y provocaba la parada de seguridad del equipo.\r\n\r\nSe procede al desmontaje de la bomba para su limpieza interior, eliminando restos acumulados en depósito, turbina y conducto de impulsión. Se realiza igualmente limpieza de bandeja de condensados y comprobación de la línea de desagüe, verificando que no existan obstrucciones adicionales. Se aplica tratamiento desinfectante para prevenir nueva acumulación prematura.\r\n\r\nUna vez montado el conjunto, se comprueba alimentación eléctrica y correcto funcionamiento del sistema de seguridad por nivel. Se realizan pruebas de funcionamiento con aporte de agua, verificando arranque y evacuación normal.\r\n\r\nEquipo queda funcionando correctamente.', 'NO', NULL, 'NO', NULL),
(12968, '2026-04933', NULL, NULL, 39, 'Visita Tecnica (No Facturable)', 0, NULL, 7, 'SAT ALMERIA', 2, 'Asignado', 3, 'No Urgente', 'NO', '2026-03-02 10:51:00', '2026-03-06', '13:45:00', '2026-03-06', '14:45:00', NULL, '01:00', 674, 'CLIENTE PARTICULAR 002', 'ESX11000019', 0, NULL, 3304, 'Félix Muñoz Rodríguez', 'PLAZA DE SAN PEDRO, 5 3º - 2', 'Almeria', '4001', 'Almería', 161, 'OFT-DAVID SANCHEZ ORTEGA', 161, 'OFT-DAVID SANCHEZ ORTEGA', NULL, NULL, NULL, 'NO', 'NO', 'VISITA TECNICA - Toma de datos y medidas para elaboración de presupuesto para sustitución de equipos.', 'Visita Técnica', NULL, 'VISITA TECNICA - Toma de datos y medidas para elaboración de presupuesto para sustitución de equipos.', NULL, 'NO', NULL, 'NO', NULL),
