(12971, '2026-04936', NULL, NULL, 2, 'Accion Correctiva', 0, NULL, 7, 'SAT ALMERIA', 2, 'Asignado', 3, 'No Urgente', 'NO', '2026-03-02 10:59:00', '2026-03-06', '10:00:00', '2026-03-06', '11:00:00', NULL, '00:00', 395, 'DISTRIBUCIONES IBERIA S.A.', 'ESX11000010', 0, NULL, 2974, 'C2119 C/ TIZIANO', 'C/ PINTOR ROSALES, 98', 'Roquetas de Mar', '4740', 'Almería', 161, 'OFT-DAVID SANCHEZ ORTEGA', 112, 'ALM-ROBERTO AGUILAR MESA', '2.0', 'SAT', NULL, 'NO', 'NO', 'Revisión diganóstica de Equipo Nº1 AA, presenta fallos.', NULL, NULL, 'Revisión diganóstica de Equipo Nº1 AA, presenta fallos.', NULL, 'NO', NULL, 'NO', NULL),
(12972, '2026-04937', '16311117', NULL, 2, 'Accion Correctiva', 0, NULL, 5, 'SAT MALAGA', 555, 'No facturar', 3, 'No Urgente', 'NO', '2026-03-02 11:47:00', '2026-03-02', '04:00:00', '2026-03-02', '05:00:00', '2026-03-02 14:37:40', '02:00', 530, 'RITMO MODA ESPAÑA,S.A.', 'ESX11000005', 130, 'ADM-CARMEN LOPEZ FERNANDEZ', 2256, '2759 ANT-LA VERONICA', 'CC	LA VERONICA	DE TALAVERA', 'ANTEQUERA', '29200', 'Málaga', 161, 'OFT-DAVID SANCHEZ ORTEGA', 135, 'MAL-DANIEL CASTAÑO RUEDA', NULL, NULL, NULL, 'NO', 'NO', 'Nº Pedido 16311117 INC000026029810 WR000977290 Nos podriais regular el aire por favor hace calor. Gracias |\r\n ', NULL, NULL, 'Nº Pedido 16311117 INC000026029810 WR000977290 Nos podriais regular el aire por favor hace calor. Gracias |\r\n ', 'tras llamar a la tienda y hacer un ajuste de 1 grado menos en la consigna de la tienda con ClimaControl. Se vuelve a llamar y me indican que están bien. Cerrado ', 'NO', NULL, 'NO', NULL),
(12973, '2026-04938', '16311242', NULL, 2, 'Accion Correctiva', 0, NULL, 13, 'SAT GRANADA', 7, 'Albaranado', 3, 'No Urgente', 'NO', '2026-03-02 11:49:00', '2026-03-02', '14:00:00', '2026-03-02', '15:00:00', '2026-03-02 22:06:20', '00:00', 591, 'MODA SUR, S.A.', 'ESX11000001', 162, 'ALM-ANDRES RIVAS TRUJILLO', 2365, '296-ARM-CC VEGA', 'HIPOCRATES Nº 16', 'ARMILLA', '18100', 'Granada', 161, 'OFT-DAVID SANCHEZ ORTEGA', 114, 'GRA-JOAQUIN LARA MEDINA', NULL, NULL, NULL, 'NO', 'NO', 'Nº Pedido 16311242 INC000026029190 WR000977182 Hace mucho calor desde esta mañana en la planta de caballero\r\n', NULL, NULL, 'Nº Pedido 16311242 INC000026029190 WR000977182 Hace mucho calor desde esta mañana en la planta de caballero\r\n', 'Se asiste a tienda tras aviso por sensación de calor durante el fin de semana. A la llegada se realizan mediciones de temperatura en diferentes puntos de sala con termómetro digital, obteniendo valores en torno a 22,5 ºC.\r\n\r\nSe comprueba estado general de la instalación, verificando funcionamiento de unidad interior y exterior, impulsión y retorno de aire, estado de filtros y correcta apertura de compuertas. Se revisan consignas de trabajo y parámetros en el sistema de control, así como histórico de alarmas, no detectándose incidencias registradas.\r\n\r\nSe realizan pruebas modificando consigna para comprobar respuesta del equipo, verificando arranque, modulación y estabilización correcta de la temperatura. Se comprueban sondas ambientales y lectura en controlador, confirmando que trabajan dentro de rango.\r\n\r\nTras tiempo de observación en funcionamiento continuo, la instalación mantiene parámetros normales y no se detectan anomalías.\r\n\r\nSe informa a responsable de tienda.', 'NO', NULL, 'NO', NULL),
(12974, '2026-04939', '16311729', NULL, 2, 'Accion Correctiva', 0, NULL, 5, 'SAT MALAGA', 7, 'Albaranado', 3, 'No Urgente', 'NO', '2026-03-02 12:43:00', '2026-03-02', '12:00:00', '2026-03-02', '13:00:00', '2026-03-02 14:37:40', '00:00', 281, 'GRUPO ELEGANCE MODA, S.A', 'ESX11000011', 130, 'ADM-CARMEN LOPEZ FERNANDEZ', 2478, '12530 MAL-MARQUES LARIOS', 'ALLE MARQUÉS DE LARIOS, 9, 29015 MÁLAGA', 'MÁLAGA', '29015', 'Málaga', 161, 'OFT-DAVID SANCHEZ ORTEGA', 135, 'MAL-DANIEL CASTAÑO RUEDA', NULL, NULL, NULL, 'NO', 'NO', 'Nº Pedido 16311729 INC000026040085 WR000978840 El sábado saltó la alarma de incendios del almacén externo y no va el aire.\r\n ', NULL, NULL, 'Nº Pedido 16311729 INC000026040085 WR000978840 El sábado saltó la alarma de incendios del almacén externo y no va el aire.\r\n ', 'Se asiste a tienda tras incidencia producida el sábado por activación del sistema de alarma de incendios, lo que provocó el disparo del general de climatización y parada completa de los equipos.\r\n\r\nSe consulta con el personal presente sobre el motivo de la activación, indicando que desconocen la causa que originó la alarma.\r\n\r\nSe realiza revisión completa de la instalación de climatización antes de proceder al rearme, comprobando estado de cuadro eléctrico general de clima, protecciones magnetotérmicas y diferenciales, así como alimentación a unidades interiores y exteriores. Se verifica que no existen daños visibles, cables afectados ni disparos parciales en equipos individuales.\r\n\r\nSe revisan controladores de las máquinas, comprobando ausencia de alarmas activas o fallos registrados derivados de la parada eléctrica. Se inspecciona secuencia de arranque para evitar picos simultáneos tras el rearme.\r\n\r\nUna vez verificadas las condiciones de seguridad, se procede al rearme del general de climatización y puesta en marcha progresiva de los equipos, controlando consumos y comportamiento en arranque.\r\n\r\nSe contacta con plataforma ClimaControl para comprobación remota del estado del sistema, verificando correcta comunicación, parámetros dentro de rango y ausencia de alarmas activas.\r\n\r\nTras periodo de observación en funcionamiento, la instalación queda operativa y trabajando con normalidad.', 'NO', NULL, 'NO', NULL),
(12975, '2026-04940', 'PTE', NULL, 2, 'Accion Correctiva', 0, NULL, 11, 'SAT CADIZ', 5, 'Finalizado', 3, 'No Urgente', 'NO', '2026-03-02 12:46:00', '2026-03-05', '08:00:00', '2026-03-05', '09:00:00', '2026-03-05 11:21:26', '00:00', 592, 'MODA SUR HOME, S.A', 'ESX11000009', 152, 'ADM-RAFAEL MORALES JIMENEZ', 2523, '403 JEREZ-CC SOL', 'AVDA. CONSTITUCION 10, 11408 JEREZ DE LA FRONTERA, CÁDIZ', 'JEREZ DE LA FRONTERA', '11408', 'Cádiz', 147, 'OFT-PABLO HERRERA MOLINA', 180, 'CAD-MANUEL HIDALGO VERA', NULL, NULL, NULL, 'NO', 'NO', 'ECO428545 Hemos detectado que la sonda STHQA-01, STHQA-02, STHQA-03 está arrojando valores erróneos', NULL, NULL, 'ECO428545 Hemos detectado que la sonda STHQA-01, STHQA-02, STHQA-03 está arrojando valores erróneos', 'se e reinicia todos los elementos de la climatización como plc térmicos de fuerza de maquinas de climatización y comunicaciones etc. se dejan otra vez en funcionamiento ', 'NO', NULL, 'NO', NULL),
