(12993, '2026-04958', 'PTE', NULL, 2, 'Accion Correctiva', 0, NULL, 5, 'SAT MALAGA', 2, 'Asignado', 3, 'No Urgente', 'NO', '2026-03-04 09:08:00', '2026-03-04', '01:00:00', '2026-03-04', '02:00:00', NULL, '00:00', 530, 'RITMO MODA ESPAÑA,S.A.', 'ESX11000005', 130, 'ADM-CARMEN LOPEZ FERNANDEZ', 2257, '104 MAL-CC CENTRO', 'CC CENTRO C/ PRINCIPAL 3', 'MÁLAGA', '29004', 'Málaga', 161, 'OFT-DAVID SANCHEZ ORTEGA', 126, 'MAL-CARLOS NAVARRO RIOS', NULL, NULL, NULL, 'NO', 'NO', 'ECO900002 Hemos detectado que la sonda UI-1.1, UI-1.2, UI-2.0, UI-3.1, UI-3.2, UI-4.1, UI-4.2 y SI-01 está arrojando valores erróneos:', NULL, NULL, 'ECO900002 Hemos detectado que la sonda UI-1.1, UI-1.2, UI-2.0, UI-3.1, UI-3.2, UI-4.1, UI-4.2 y SI-01 está arrojando valores erróneos:', NULL, 'NO', NULL, 'NO', NULL),
(12994, '2026-04959', '90000009', NULL, 2, 'Accion Correctiva', 0, NULL, 16, 'SAT SEVILLA/HUELVA', 555, 'No facturar', 3, 'No Urgente', 'NO', '2026-03-04 10:06:00', '2026-03-04', '01:00:00', '2026-03-04', '03:00:00', '2026-03-04 16:05:41', '00:00', 464, 'COSTA JOVEN ESPAÑA S.A.', 'ESX11000004', 152, 'ADM-RAFAEL MORALES JIMENEZ', 2385, '305 SEV-CC PONIENTE', 'AVDA. DE LOS NARANJOS', 'SEVILLA', '41014', 'Sevilla', 147, 'OFT-PABLO HERRERA MOLINA', 164, 'SEV-MARCOS GUTIERREZ CANO', NULL, NULL, NULL, 'NO', 'NO', 'WR000900008 Hace frio en la zona de ventas.', NULL, NULL, 'WR000900008 Hace frio en la zona de ventas.', 'solucionado por telefono', 'NO', NULL, 'NO', NULL),
(12995, '2026-04960', 'PTE', NULL, 2, 'Accion Correctiva', 0, NULL, 11, 'SAT CADIZ', 5, 'Finalizado', 3, 'No Urgente', 'NO', '2026-03-04 10:27:00', '2026-03-05', '01:00:00', '2026-03-05', '02:00:00', '2026-03-05 16:11:41', '00:00', 607, 'IBERIA BUILDING SERVICES, SLU', 'ESX11000008', 152, 'ADM-RAFAEL MORALES JIMENEZ', 3132, 'SABORES DEL SUR CADIZ - CONIL', 'C/ DEL RIO 15', 'Conil de la Frontera', '11140', 'Cádiz', 147, 'OFT-PABLO HERRERA MOLINA', 180, 'CAD-MANUEL HIDALGO VERA', NULL, NULL, NULL, 'NO', 'NO', 'hemos tenido un problema con el aire, soltaba agua y ha creado humedad en la pared y necesitamos reparar también esta fuga', NULL, NULL, 'hemos tenido un problema con el aire, soltaba agua y ha creado humedad en la pared y necesitamos reparar también esta fuga', 'se desmonta malla situada en la fachada donde se encuentra ubicadas la unidades exteriores,se abre hueco por debajo de dichas unidades para poder ver donde acaban los condensados ,se observa tiene instalado una bomba de condensador para llevar el agua producida por las máquinas a un tubo de desagüe,se comprueban dicha bomba forzándola a evacuar bastantes litros de agua y funciona correctamente y no se observa ninguna fuga de agua por ningún sitio así q se descarta q se problemas con la instalación de los equipos de climatizacion.', 'NO', NULL, 'NO', NULL),
(12996, '2026-04961', '#106858', NULL, 2, 'Accion Correctiva', 0, NULL, 7, 'SAT ALMERIA', 2, 'Asignado', 3, 'No Urgente', 'NO', '2026-03-04 12:00:00', '2026-03-04', '13:00:00', '2026-03-04', '14:30:00', NULL, '00:00', 239, 'GESTIONA FACILITY SERVICES SL', 'ESX11000007', 0, NULL, 2965, 'DEPORTES CC LEVANTE ROQUETAS', 'C/ MEDITERRANEO S/N, CC LEVANTE L-43', 'Roquetas de Mar', '4740', 'Almería', 161, 'OFT-DAVID SANCHEZ ORTEGA', 108, 'ALM-DIEGO MOLINA BRAVO', NULL, NULL, NULL, 'NO', 'NO', 'Visita técnica para diagnóstico.\r\nRevisión equipo para elaboración de presupuesto.', NULL, 'Detallar el problema.', 'Visita técnica para diagnóstico.\r\nRevisión equipo para elaboración de presupuesto.', 'recuperador fuera de servicio se comprueba si le llega alimentación y no llegaba al recuperador tras las comprobaciones sigo el cableado y en el cuadro tiene un temporizador que estaba en la posición cero y por eso no llegaba alimentación se pone en funcionamiento y se queda funcionando correctamente ', 'NO', NULL, 'NO', NULL),
(12997, '2026-04962', '90000008', NULL, 2, 'Accion Correctiva', 0, NULL, 5, 'SAT MALAGA', 7, 'Albaranado', 3, 'No Urgente', 'NO', '2026-03-04 12:48:00', '2026-03-04', '05:00:00', '2026-03-04', '06:00:00', '2026-03-05 09:10:58', '02:00', 591, 'MODA SUR, S.A.', 'ESX11000001', 130, 'ADM-CARMEN LOPEZ FERNANDEZ', 2325, '202 MARB-EL PINAR', 'C/ LOS PINOS', 'MARBELLA', '29600', 'Málaga', 133, 'OFT-SERGIO TORRES REYES', 158, 'MAL-IVAN PEREZ GALLARDO', NULL, NULL, NULL, 'NO', 'NO', 'Nº Pedido 90000008 WR000900007 Es imposible estar en la zona de caja de caballero hace muchísimo frio', '[C]', '[COMPLETO]', 'Nº Pedido 90000008 WR000900007 Es imposible estar en la zona de caja de caballero hace muchísimo frio', 'Se acude a tienda por incidencia de disconfort térmico en sala de ventas. A la llegada se realiza comprobación de la temperatura ambiente en diferentes zonas de la tienda para contrastar con los valores registrados en el sistema de control de climatización.\r\n\r\nDurante la intervención se revisa el control del sistema y parámetros configurados en el controlador, verificando el funcionamiento de las sondas de temperatura y las consignas activas del equipo. Se detecta que la temperatura de consigna configurada no se ajusta a las condiciones reales de funcionamiento de la instalación, provocando un control incorrecto de la climatización.\r\n\r\nSe procede a realizar ajuste de la temperatura de consigna en el sistema de control, así como verificación de los parámetros de regulación asociados para asegurar un funcionamiento estable del equipo. Tras la modificación se realizan pruebas de funcionamiento y seguimiento del sistema, comprobando la correcta respuesta de los equipos y la estabilización progresiva de la temperatura en la zona de ventas.\r\n\r\nLa instalación queda funcionando correctamente y dentro de parámetros normales de confort tras los ajustes realizados.', 'NO', NULL, 'NO', NULL),
